    "signature": "ADVC.MakeProcess.ModalFreqResp(strName, strRefEigenDir=\"\", dRefLowFreq=DFLT_DBL, dRefHighFreq=DFLT_DBL, crModalDampingRatio=None, crExcitationFreq=None, bAutoFreqInterval=False, dMaxFreq=DFLT_DBL, dMinFreq=DFLT_DBL, iNumFreqPoint=DFLT_INT, dBiasParam=DFLT_DBL, crEdit=None, listLoadNode=[], listLoadCaseNode=[], listLoadNodeContact=[], ilOutputParamList=[], iRefType=-1, strRefPath=\"\", listAdvcRefStressResult=[], strRefPathOfTempLoad=\"\", iRefProcessOfTempLoad=DFLT_INT)",
