    "signature": "BoundaryConditions.EnforcedLoads.Acceleration(strName=\"EnforcedAcceleration1\", dAccelUx=DFLT_DBL, dAccelUy=DFLT_DBL, dAccelUz=DFLT_DBL, dAccelRx=DFLT_DBL, dAccelRy=DFLT_DBL, dAccelRz=DFLT_DBL, crCurCoord=None, iArrowDir=0, crTable=None, dPhase=DFLT_DBL, dDelay=DFLT_DBL, crPhaseTable=None, bExport=False, crMEExportUx=None, crMEExportUy=None, crMEExportUz=None, crMEExportRx=None, crMEExportRy=None, crMEExportRz=None, iAccelTransUnit=0, iAccelRotUnit=0, crlTargets=[], crEdit=None)",
