    "prefix": "ConnectionCopyTranslate",
    "signature": "BoundaryConditions.LBCCopy.ConnectionCopyTranslate(iMethod=0, iMatchMethod=0, posVecTrans=[0,0,0], dMagnitude=1, dTrandataDoffset=0.0, dTol=1, crCoord=None, crlTargets=[])",
