    "prefix": "ResponseCondition",
    "signature": "Calculation.FreqResp.ResponseCondition(crTargetAnalysis=None, crCoordinate=None, bAllModesUsed=True, strlModesSelected=[], bDampingFactor=True, dDampingFactor=0.01, crDampingFactor=None, iCurveStyle=1, dStyleParamTop=0.0, dStyleParamMid=1.0, dStyleParamBot=1.0, bIncludeEigenValue=False, bCreateNewResult=False, iResultType=0, strlResultNames=[\"TX\"], iResultPosition=0, bAllLoadCases=True, crSelectedLoadCase=None, bSeparateLoad=False, crlTargets=[], crEdit=None)",
