    "prefix": "Cylinder",
    "signature": "Geometry.Part.Cylinder(strName=\"Cylinder_1\", crLocalCoordinate=None, bHollow=False, bTapered=False, dlOrigin=[0.0,0.0,0.0], dTopInnerRadius=0.001, dTopOuterRadius=0.01, dBottomInnerRadius=0.001, dBottomOuterRadius=0.01, dHeight=0.01, iCircularNodes=36, iAxialNodes=10, iPartColor=7105764)",
