      "dAxisMaxSize=3e-3",
      "bAxisMaxSize=True",
      "iAxisMinMeshCount=1",
      "bAxisMinMeshCount=True",
      "iElementType=0",
      "dSingleLayerLength=1e-3",
      "bSingleLayerLength=True",
